#include <stdio.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    const char *data =
        "root:x:0:0:root:/root:/bin/bash\n"
        "daemon:x:1:1:daemon:/usr/sbin:/usr/sbin/nologin\n"
        "alice:x:1000:1000:Alice:/home/alice:/bin/bash\n";
    FILE *f = fmemopen((void *)data, strlen(data), "r");
    if (!f) return 1;
    char line[256], login[64];
    int uid;
    printf("login,uid\n");
    while (fgets(line, sizeof(line), f)) { // ★ lit jusqu'à \n ou EOF
        line[strcspn(line, "\n")] = 0; // ★ retire le \n trailing
        if (sscanf(line, "%63[^:]:%*[^:]:%d", login, &uid) == 2) // ★ parse champ1:champ2(skip):champ3
            printf("%s,%d\n", login, uid);
    }
    fclose(f);
    return 0;
}

